import React, { useState, useEffect, useCallback } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Typography,
  Button,
  CircularProgress,
  Stack,
  Alert,
  Snackbar,
  LinearProgress
} from '@mui/material';
import {
  Refresh as RefreshIcon,
  PlayArrow as StartIcon,
  Stop as StopIcon,
  Sync as SyncIcon
} from '@mui/icons-material';
import { getSystemInfo, getSystemStatus, startService, stopService, restartService, getRealtimeTraffic } from '../services/api';
import { motion } from 'framer-motion';

const UPDATE_INTERVAL = 5000; // 5 seconds

const Dashboard = () => {
  const [systemInfo, setSystemInfo] = useState(null);
  const [subscriptions, setSubscriptions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [realtimeTraffic, setRealtimeTraffic] = useState(null);

  const fetchDashboardData = useCallback(async () => {
    try {
      setLoading(true);
      const [info, status] = await Promise.all([
        getSystemInfo(),
        getSystemStatus()
      ]);
      setSystemInfo(info);
      setSubscriptions(status.subscriptions || []);
      setError(null);
    } catch (err) {
      setError(err.response?.data?.error || '获取仪表盘数据失败');
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchRealtimeTraffic = useCallback(async () => {
    try {
      const data = await getRealtimeTraffic();
      setRealtimeTraffic(data);
    } catch (err) {
      console.error('Failed to fetch realtime traffic:', err);
    }
  }, []);

  useEffect(() => {
    fetchDashboardData();
    const dashboardInterval = setInterval(fetchDashboardData, UPDATE_INTERVAL);
    const trafficInterval = setInterval(fetchRealtimeTraffic, 1000);
    return () => {
      clearInterval(dashboardInterval);
      clearInterval(trafficInterval);
    };
  }, [fetchDashboardData, fetchRealtimeTraffic]);

  const handleServiceAction = async (action, serviceName) => {
    try {
      setLoading(true);
      switch (action) {
        case 'start':
          await startService(serviceName);
          break;
        case 'stop':
          await stopService(serviceName);
          break;
        case 'restart':
          await restartService(serviceName);
          break;
        default:
          throw new Error('Invalid action');
      }
      setSuccess(true);
      await fetchDashboardData();
    } catch (err) {
      setError(err.response?.data?.error || '操作失败');
    } finally {
      setLoading(false);
    }
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const CircularProgressWithLabel = ({ value, size = 120, thickness = 4, color = 'primary' }) => (
    <Box sx={{ position: 'relative', display: 'inline-flex' }}>
      <CircularProgress
        variant="determinate"
        value={value}
        size={size}
        thickness={thickness}
        sx={{
          color: (theme) => theme.palette[color].main,
          circle: {
            strokeLinecap: 'round',
          },
        }}
      />
      <Box
        sx={{
          top: 0,
          left: 0,
          bottom: 0,
          right: 0,
          position: 'absolute',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        <Typography variant="h6" component="div" color={color}>
          {value}%
        </Typography>
        <Typography variant="caption" component="div" color="text.secondary">
          使用率
        </Typography>
      </Box>
    </Box>
  );

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0 }
  };

  if (!systemInfo && loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Box sx={{ mb: 3 }}>
        <Typography variant="h5" gutterBottom>仪表盘</Typography>
      </Box>

      {loading && <LinearProgress sx={{ mb: 2 }} />}

      <motion.div
        initial="hidden"
        animate="visible"
        variants={{
          visible: {
            transition: {
              staggerChildren: 0.1
            }
          }
        }}
      >
        <Grid container spacing={3}>
          {/* Device Information */}
          <Grid item xs={12} md={3}>
            <motion.div variants={cardVariants}>
              <Card>
                <CardContent>
                  <Typography variant="h6" gutterBottom>设备信息</Typography>
                  <Stack spacing={1.5}>
                    <Box>
                      <Typography variant="body2" color="text.secondary">主机名: {systemInfo?.hostname}</Typography>
                      <Typography variant="body2" color="text.secondary">操作系统: {systemInfo?.platform}</Typography>
                      <Typography variant="body2" color="text.secondary">内核版本: {systemInfo?.kernelVersion}</Typography>
                      <Typography variant="body2" color="text.secondary">平台: {systemInfo?.platform}</Typography>
                      <Typography variant="body2" color="text.secondary">架构: {systemInfo?.arch}</Typography>
                      <Typography variant="body2" color="text.secondary">运行时间: {systemInfo?.uptime}</Typography>
                    </Box>
                  </Stack>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          {/* System Metrics */}
          <Grid item xs={12} md={3}>
            <motion.div variants={cardVariants}>
              <Card>
                <CardContent sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                  <Typography variant="h6" gutterBottom>系统资源</Typography>
                  <Stack spacing={3} alignItems="center">
                    <CircularProgressWithLabel value={systemInfo?.cpu || 1} color="primary" />
                    <Box sx={{ width: '100%' }}>
                      <Typography variant="body2" color="text.secondary" gutterBottom align="center">
                        CPU 核心数: {systemInfo?.cpuCores || 'N/A'}
                      </Typography>
                      <Typography variant="body2" color="text.secondary" align="center">
                        CPU 频率: {systemInfo?.cpuFreq || 'N/A'} MHz
                      </Typography>
                    </Box>
                  </Stack>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          {/* Memory Usage */}
          <Grid item xs={12} md={3}>
            <motion.div variants={cardVariants}>
              <Card>
                <CardContent sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                  <Typography variant="h6" gutterBottom>内存使用</Typography>
                  <Stack spacing={3} alignItems="center">
                    <CircularProgressWithLabel value={systemInfo?.memory || 13} color="secondary" />
                    <Box sx={{ width: '100%' }}>
                      <Typography variant="body2" color="text.secondary" gutterBottom align="center">
                        总内存: {formatBytes(systemInfo?.totalMemory || 0)}
                      </Typography>
                      <Typography variant="body2" color="text.secondary" align="center">
                        可用内存: {formatBytes(systemInfo?.availableMemory || 0)}
                      </Typography>
                    </Box>
                  </Stack>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          {/* Network Traffic */}
          <Grid item xs={12} md={3}>
            <motion.div variants={cardVariants}>
              <Card>
                <CardContent>
                  <Typography variant="h6" gutterBottom>网络流量</Typography>
                  <Stack spacing={2}>
                    <Box>
                      <Typography variant="body2" color="text.secondary" gutterBottom>
                        上传速度: {formatBytes(realtimeTraffic?.upload || 0)}/s
                      </Typography>
                      <LinearProgress 
                        variant="determinate" 
                        value={Math.min((realtimeTraffic?.upload || 0) / 1048576 * 100, 100)}
                        sx={{ mb: 1, height: 6 }}
                        color="success"
                      />
                    </Box>
                    <Box>
                      <Typography variant="body2" color="text.secondary" gutterBottom>
                        下载速度: {formatBytes(realtimeTraffic?.download || 0)}/s
                      </Typography>
                      <LinearProgress 
                        variant="determinate" 
                        value={Math.min((realtimeTraffic?.download || 0) / 1048576 * 100, 100)}
                        sx={{ height: 6 }}
                        color="primary"
                      />
                    </Box>
                    <Box>
                      <Typography variant="body2" color="text.secondary" gutterBottom>
                        总上传: {formatBytes(realtimeTraffic?.totalUp || 0)}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        总下载: {formatBytes(realtimeTraffic?.totalDown || 0)}
                      </Typography>
                    </Box>
                  </Stack>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          {/* Service Cards */}
          <Grid item xs={12} md={6}>
            <motion.div variants={cardVariants}>
              <Card>
                <CardContent>
                  <Typography variant="h6" gutterBottom>Singbox</Typography>
                  <Stack spacing={2}>
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <Stack spacing={1}>
                        <Typography variant="body2" color="text.secondary">版本: {systemInfo?.singbox?.version}</Typography>
                        <Typography variant="body2" color="text.secondary">启动时间: {systemInfo?.singbox?.startTime}</Typography>
                        <Typography variant="body2" color="text.secondary">
                          状态: 
                          <Box
                            component="span"
                            sx={{
                              color: systemInfo?.singbox?.status === 'running' ? 'success.main' : 'error.main',
                              ml: 1
                            }}
                          >
                            {systemInfo?.singbox?.status}
                          </Box>
                        </Typography>
                      </Stack>
                      <Stack direction="row" spacing={1}>
                        <Button
                          variant="outlined"
                          color={systemInfo?.singbox?.status === 'running' ? 'error' : 'success'}
                          onClick={() => handleServiceAction(
                            systemInfo?.singbox?.status === 'running' ? 'stop' : 'start',
                            'singbox'
                          )}
                          disabled={loading}
                        >
                          {systemInfo?.singbox?.status === 'running' ? '停止' : '启动'}
                        </Button>
                        <Button
                          variant="outlined"
                          onClick={() => handleServiceAction('restart', 'singbox')}
                          disabled={loading}
                        >
                          重启
                        </Button>
                      </Stack>
                    </Box>
                  </Stack>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          {/* Mosdns Card */}
          <Grid item xs={12} md={6}>
            <motion.div variants={cardVariants}>
              <Card>
                <CardContent>
                  <Typography variant="h6" gutterBottom>Mosdns</Typography>
                  <Stack spacing={2}>
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <Stack spacing={1}>
                        <Typography variant="body2" color="text.secondary">版本: {systemInfo?.mosdns?.version}</Typography>
                        <Typography variant="body2" color="text.secondary">启动时间: {systemInfo?.mosdns?.startTime}</Typography>
                        <Typography variant="body2" color="text.secondary">
                          状态: 
                          <Box
                            component="span"
                            sx={{
                              color: systemInfo?.mosdns?.status === 'running' ? 'success.main' : 'error.main',
                              ml: 1
                            }}
                          >
                            {systemInfo?.mosdns?.status}
                          </Box>
                        </Typography>
                      </Stack>
                      <Stack direction="row" spacing={1}>
                        <Button
                          variant="outlined"
                          color={systemInfo?.mosdns?.status === 'running' ? 'error' : 'success'}
                          onClick={() => handleServiceAction(
                            systemInfo?.mosdns?.status === 'running' ? 'stop' : 'start',
                            'mosdns'
                          )}
                          disabled={loading}
                        >
                          {systemInfo?.mosdns?.status === 'running' ? '停止' : '启动'}
                        </Button>
                        <Button
                          variant="outlined"
                          onClick={() => handleServiceAction('restart', 'mosdns')}
                          disabled={loading}
                        >
                          重启
                        </Button>
                      </Stack>
                    </Box>
                  </Stack>
                </CardContent>
              </Card>
            </motion.div>
          </Grid>

          {/* Subscriptions */}
          <Grid item xs={12}>
            <motion.div variants={cardVariants}>
              <Box sx={{ mb: 2, display: 'flex', alignItems: 'center' }}>
                <Typography variant="h6" sx={{ flexGrow: 1 }}>订阅</Typography>
                <Button
                  startIcon={<SyncIcon />}
                  size="small"
                  onClick={fetchDashboardData}
                  disabled={loading}
                >
                  刷新
                </Button>
              </Box>
              <Grid container spacing={2}>
                {subscriptions.map((sub) => (
                  <Grid item xs={12} sm={6} md={3} key={sub.id}>
                    <motion.div variants={cardVariants}>
                      <Card>
                        <CardContent>
                          <Typography variant="h6" gutterBottom>{sub.name}</Typography>
                          <Stack spacing={2}>
                            <Typography variant="body2" color="text.secondary">
                              更新时间: {sub.updateTime}
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                              到期时间: {sub.expireTime}
                            </Typography>
                            <Box>
                              <Typography variant="body2" color="text.secondary" gutterBottom>
                                流量使用: {formatBytes(sub.usedTraffic)} / {formatBytes(sub.totalTraffic)}
                              </Typography>
                              <LinearProgress 
                                variant="determinate" 
                                value={(sub.usedTraffic / sub.totalTraffic) * 100}
                                sx={{ 
                                  height: 6, 
                                  borderRadius: 3,
                                  bgcolor: (theme) => 
                                    theme.palette.mode === 'dark' 
                                      ? 'rgba(255, 255, 255, 0.12)' 
                                      : 'rgba(0, 0, 0, 0.08)',
                                  '.MuiLinearProgress-bar': {
                                    borderRadius: 3,
                                  }
                                }}
                              />
                            </Box>
                          </Stack>
                        </CardContent>
                      </Card>
                    </motion.div>
                  </Grid>
                ))}
              </Grid>
            </motion.div>
          </Grid>
        </Grid>
      </motion.div>
    </Box>
  );
};

export default Dashboard;
